// CHECK: lhu	a0, 0(a1)
// CHECK-ASM-SAME: # encoding: [0x03,0xd5,0x05,0x00]
// CHECK-ASM-NEXT: # <MCInst #[[#MCINST4:]] LHU{{$}}
